1	export const runScenario = (scenario: unknown): { results: unknown[] } => {
2	  return { results: [{ premium: 5 }] };
3	};
4

1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // --- Edge case: empty item list ---
6	  it("empty item list → premium 5 G (only the processing fee)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result.results[0]).toEqual({ premium: 5 });
12	  });
13	
14	  // --- Base premiums for main items (base + 5 G fee, first insurance +10%) ---
15	  // Note: a single first item carries first-insurance surcharge; tests use customer history to isolate.
16	  it.todo("single sword, no modifiers → base premium 100 G");
17	  it.todo("single amulet, no modifiers → base premium 60 G");
18	  it.todo("single staff, no modifiers → base premium 80 G");
19	  it.todo("single potion, no modifiers → base premium 40 G");
20	
21	  // --- Components and building blocks ---
22	  it.todo("2 runes → 50 G base premium (no block)");
23	  it.todo("3 runes → 60 G base premium (block applies)");
24	  it.todo("4 runes → 100 G base premium (no block — block requires exactly 3)");
25	  it.todo("7 runes → 175 G base premium");
26	
27	  // --- "Alike" components ---
28	  it.todo("2 runes + 1 moonstone → 75 G base premium (no block: different types)");
29	  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks)");
30	
31	  // --- Premium modifiers in isolation ---
32	  it.todo("cursed item adds 50 % risk surcharge of its base premium");
33	  it.todo("highly enchanted item (enchantment ≥ 5) adds 30 % risk surcharge");
34	  it.todo("long-standing customer (≥ 2 years) receives 20 % loyalty discount");
35	  it.todo("first insurance carries 10 % initial assessment surcharge");
36	  it.todo("each contract after the first receives 15 % follow-up discount");
37	  it.todo("5 G processing fee is added to every premium");
38	
39	  // --- Modifier scope on multi-item policies ---
40	  it.todo("cursed sword + plain amulet → 210 G before fee (surcharge on cursed item's base only)");
41	  it.todo("item modifiers apply per item; policy modifiers apply to policy base; fee added last");
42	
43	  // --- Modifier thresholds ---
44	  it.todo("customer with exactly 2 years → loyalty discount applies");
45	  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies");
46	  it.todo("sword with exactly enchantment 5 and cursed → both surcharges apply");
47	  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
48	
49	  // --- Rounding in the MHPCO's favor ---
50	  it.todo("premium 197.5 G → final premium 198 G (rounded up)");
51	  it.todo("payout 350.5 G → final payout 350 G (rounded down)");
52	
53	  // --- Claim processing: standard reimbursement ---
54	  it.todo("regular sword, damage 500 G → payout 400 G (full minus 100 G deductible)");
55	  it.todo("rune damage 200 G → payout 100 G (no special clause; minus deductible)");
56	
57	  // --- Enchantment threshold vs dragon material ---
58	  it.todo("dragon sword, enchantment 8, damage 1000 G → payout 400 G (50 % then deductible)");
59	  it.todo("dragon sword, enchantment 9, damage 1000 G → payout 400 G (both clauses; 50 % wins)");
60	  it.todo("dragon sword, enchantment 5, damage 800 G → payout 700 G (full then deductible)");
61	  it.todo("steel sword, enchantment 9, damage 1000 G → payout 400 G (50 % then deductible)");
62	
63	  // --- Deductible per damage event ---
64	  it.todo("dragon attack damages sword 500 G and amulet 300 G → payout 600 G (deductible per item)");
65	
66	  // --- Multiple items of the same type ---
67	  it.todo("policy covers two swords → insurance sum 2000 G, cap 4000 G");
68	  it.todo("two sword damages on two-sword policy → each treated as separate damage with own deductible");
69	  it.todo("more damages of a type than insured (two sword damages, one sword) → claim rejected (nonzero exit)");
70	
71	  // --- Cap exhaustion ---
72	  it.todo("sword + amulet → insurance sum 1600 G, cap 3200 G");
73	  it.todo("cursed sword → cap 2000 G (based on unmodified insurance value)");
74	  it.todo("sword + 3 runes (block) → insurance sum 1750 G (block affects premium only)");
75	  it.todo("two successive 1500 G claims on 1000 G sword → payouts 1400 G then 600 G, cap remaining 600 then 0");
76	
77	  // --- Edge cases: errors ---
78	  it.todo("quote with unknown item type (broomstick) → nonzero exit, error on stderr, no results on stdout");
79	  it.todo("claim references item not in policy (amulet when only sword insured) → nonzero exit, error on stderr");
80	  it.todo("claim with negative damage amount (-200) → nonzero exit, error on stderr");
81	
82	  // --- Integration examples ---
83	  it.todo("newcomer with cursed sword (enchantment 3) → premium 165 G");
84	  it.todo("long-standing customer's second contract, cursed sword enchantment 7 → premium 160 G");
85	
86	  // --- CLI / scenario plumbing ---
87	  it.todo("results array has same length and order as input steps");
88	});
